import React from 'react';

const colorMap = {
  green: 'bg-emerald-50 text-emerald-700 border-emerald-200',
  red: 'bg-red-50 text-red-700 border-red-200',
  yellow: 'bg-amber-50 text-amber-700 border-amber-200',
  blue: 'bg-blue-50 text-blue-700 border-blue-200',
  violet: 'bg-violet-50 text-violet-700 border-violet-200',
  slate: 'bg-slate-50 text-slate-600 border-slate-200',
  cyan: 'bg-cyan-50 text-cyan-700 border-cyan-200',
  orange: 'bg-orange-50 text-orange-700 border-orange-200',
  purple: 'bg-purple-50 text-purple-700 border-purple-200',
};

const dotMap = {
  green: 'bg-emerald-500',
  red: 'bg-red-500',
  yellow: 'bg-amber-500',
  blue: 'bg-blue-500',
  violet: 'bg-violet-500',
  slate: 'bg-slate-400',
  cyan: 'bg-cyan-500',
  orange: 'bg-orange-500',
  purple: 'bg-purple-500',
};

const statusColors = {
  Active: 'green',
  Completed: 'slate',
  Pending: 'yellow',
  Rejected: 'red',
  Open: 'blue',
  Closed: 'slate',
  Paused: 'orange',
};

const typeColors = {
  'Bug Hunt': 'red',
  Usability: 'blue',
  'Load Test': 'yellow',
  'Multi-Day': 'slate',
  Fintech: 'green',
  Game: 'orange',
  'Global QA': 'cyan',
  Accessibility: 'blue',
  QA: 'slate',
};

export function Badge({ label, color, dot = false, className = '' }) {
  const resolvedColor = color || statusColors[label] || 'slate';
  const colorClass = colorMap[resolvedColor] || colorMap.slate;
  const dotClass = dotMap[resolvedColor] || dotMap.slate;

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-2.5 py-1 text-xs font-medium rounded-full border ${colorClass} ${className}`}
    >
      {dot && <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${dotClass}`} />}
      {label}
    </span>
  );
}

export function StatusBadge({ status }) {
  return <Badge label={status} dot />;
}

export function TypeBadge({ type }) {
  return <Badge label={type} color={typeColors[type]} />;
}

export function SeverityBadge({ count, type = 'issues' }) {
  const color = count === 0 ? 'green' : count <= 5 ? 'yellow' : count <= 20 ? 'orange' : 'red';
  return <Badge label={`${count} ${type}`} color={color} />;
}
